const handleSubmit = (e) => {
    e.preventDefault();
    if(!ciudad) return alert("Por favor, selecciona la ciudad");
    
    // Enviamos lat y lng por separado para que el calculador las encuentre fácil
    onSave({ 
      nombre, 
      direccion, 
      provincia, 
      ciudad, 
      lat: coords[0], // Primera parte del array
      lng: coords[1]  // Segunda parte del array
    });
  };
